"""
MKT Christ Commentary — Isaiah chapter 2
Run: python3 scripts/zc-christ-isaiah-2.py

Isaiah 2 divides into two contrasting visions:
1. vv.1-5: The eschatological pilgrimage of nations to Zion — the universal peace oracle
2. vv.6-22: The Day of YHWH — the humiliation of all human pride

Both sections are extensively used in NT proclamation:
- The pilgrimage oracle establishes the framework for the church as the eschatological
  gathering of nations; Paul's mission to the Gentiles is the actualization of 2:2-4.
- The Day of YHWH material (vv.10-21) underlies Revelation 6:15-17 and Jesus's
  passion-week oracles about judgment.

Key Christological readings:
- 2:2-4: the "last days" (bĕʾaḥărît hayyāmîm) = the messianic era; Acts 2:17;
  Heb 1:2; the Torah going forth from Zion = Christ as the new Torah (John 1:1,14)
- 2:4: swords into plowshares — fulfilled in the peace Christ makes (Eph 2:14-15)
- 2:5: "walk in the light of YHWH" = John 8:12; 1 John 1:5-7
- 2:10-21: hiding from divine wrath — Rev 6:15-17; Luke 23:30
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {
  "2": {
    "1": '<p>The chapter\'s heading (<em>haddābār ʾăšer ḥāzâ yĕšaʿyāhû</em>) identifies prophetic vision as "the word that Isaiah saw" — vision (<em>ḥāzôn</em>) and word (<em>dābār</em>) are united. In the NT, this unity of seeing and hearing reaches its apex in the Prologue of John (1:1-14): the Word that was in the beginning, heard and seen by the eyewitnesses (1 John 1:1-3, "what we have heard, what we have seen with our eyes, what we looked upon and touched with our hands"). The prophetic word is proto-incarnational: it comes from YHWH, takes form in time, and demands reception.</p>',
    "2": '<p>"It shall come to pass in the latter days (<em>bĕʾaḥărît hayyāmîm</em>) that the mountain of YHWH\'s house shall be established as the highest of the mountains." The phrase <em>bĕʾaḥărît hayyāmîm</em> (in the last/latter days) is programmatically used in Acts 2:17 where Peter, citing Joel 2:28-32, announces "in the last days, God declares, I will pour out my Spirit" — the Pentecost is the inauguration of the <em>ʾaḥărît hayyāmîm</em>. Hebrews 1:2 announces "in these last days he has spoken to us by his Son." The "latter days" of Isaiah 2:2 = the age that began with the incarnation and Pentecost. The "mountain of YHWH\'s house" that all nations stream to is the eschatological Zion whose fullness Revelation 21:22-27 describes — the New Jerusalem needs no temple "for its temple is the Lord God the Almighty and the Lamb," and "the nations will walk by its light."</p>',
    "3": '<p>"Many peoples shall come and say: Come, let us go up to the mountain of YHWH, to the house of the God of Jacob, that he may teach us his ways and that we may walk in his paths. For from Zion shall go forth Torah (<em>tôrâ</em>), and the word of YHWH from Jerusalem." The going-forth of Torah from Zion is fulfilled in Christ who is the Word from the Father (John 1:1, 14) and the fulfillment of the Torah (Matt 5:17: "I have not come to abolish the Torah but to fulfill it"). The missionary sending of Acts 1:8 ("you will be my witnesses in Jerusalem, and in all Judea and Samaria, and to the ends of the earth") is the actualization of the word going forth from Jerusalem. Paul reads his own Gentile mission as the fulfillment of passages like this (Rom 15:18-21), going where the name of Christ has not been named in obedience to the eschatological gathering of nations.</p>',
    "4": '<p>"He shall judge between the nations and shall decide disputes for many peoples; and they shall beat their swords into plowshares, and their spears into pruning hooks; nation shall not lift up sword against nation, neither shall they learn war anymore." The Christological reception is threefold. (1) Christ as eschatological judge: John 5:22 ("the Father judges no one, but has given all judgment to the Son"); Acts 17:31 ("he has fixed a day on which he will judge the world in righteousness by a man whom he has appointed"). (2) The peace achieved through Christ: Eph 2:14-15 ("he himself is our peace, who has made us both one and has broken down in his flesh the dividing wall of hostility"). (3) The swords-to-plowshares reversal of Joel 3:10 ("beat your plowshares into swords") in Isaiah creates an eschatological polarity: the call to war before judgment, the transformation to peace after it — Christ stands at the fulcrum, first the servant who makes peace by the cross, then the judge who enforces it at his return.</p>',
    "5": '<p>"O house of Jacob, come, let us walk in the light of YHWH." The appeal to "walk in the light" of YHWH becomes in the NT the fundamental description of the Christian life. John 8:12: "I am the light of the world; whoever follows me will not walk in darkness, but will have the light of life." 1 John 1:5-7: "God is light, and in him is no darkness at all. If we say we have fellowship with him while we walk in darkness, we lie and do not practice the truth. But if we walk in the light, as he is in the light, we have fellowship with one another." The light of YHWH in Isaiah 2:5 is the light that comes into the world in Jesus (John 1:9-11), which the darkness could not overcome (1:5).</p>',
    "6": '<p>"For you have rejected your people, the house of Jacob, because they are full of things from the east and of fortune-tellers like the Philistines, and they strike hands with the children of foreigners." The abandonment of the people to foreign religious practices is the judgment that precedes the Day of YHWH. In NT terms, this chapter\'s structure of rejection followed by eschatological vindication maps onto the pattern of Israel\'s rejection of Christ and the subsequent opening of the Gentile mission (Rom 11:11-12: "through their trespass salvation has come to the Gentiles, so as to make Israel jealous"). The "things from the east" and fortune-telling represent the syncretism that Jesus condemns in the religious leaders who "devour widows\' houses" and "say a long prayer" while rejecting the covenant\'s weightier matters (Matt 23:23).</p>',
    "7": '<p>"Their land is filled with silver and gold, and there is no end to their treasures; their land is filled with horses, and there is no end to their chariots." The accumulation of wealth and military power violates the Deuteronomic restriction on the king (Deut 17:16-17: "he must not acquire many horses... he must not acquire much silver and gold"). Jesus\'s teaching inverts this entirely: "lay not up treasures on earth" (Matt 6:19-20); "you cannot serve God and money" (6:24); the rich young ruler who turns away from discipleship because of his possessions (Mark 10:22). The land filled with treasures and horses is the opposite of the kingdom of God, which belongs to the poor in spirit (Matt 5:3).</p>',
    "8": '<p>"Their land is filled with idols; they bow down to the work of their hands, to what their own fingers have made." Paul\'s Areopagus sermon (Acts 17:29-30) draws on this exact critique: "Being then God\'s offspring, we ought not to think that the divine being is like gold or silver or stone, an image formed by the art and imagination of man. The times of ignorance God overlooked, but now he commands all people everywhere to repent." The idol as "work of human hands" (<em>maʿăśēh yĕḏêhem</em>) becomes in the NT a comprehensive description of all autonomous human construction that refuses to receive the living God. Col 3:5 identifies covetousness itself as idolatry, extending the concept beyond cultic images.</p>',
    "9": '<p>"So man is humbled, and each one is brought low — do not forgive them!" The humbling of humanity (<em>wayyiššaḥ ʾādām wayyiššāpel ʾîš</em>) in vv.9,11,12,17 establishes the chapter\'s dominant theme: the eschatological reversal of all human pretension. In Christ, this reversal takes the form of the Magnificat (Luke 1:51-53: "he has scattered the proud in the thoughts of their hearts; he has brought down the mighty from their thrones and exalted those of humble estate"). The refusal of forgiveness in this verse must be read canonically — it is the appropriate response to specific, unrepented covenant violations. The cross, which this same Isaiah anticipates (ch. 53), is precisely where YHWH does not invoke the unforgiveness of 2:9 but absorbs the judgment himself.</p>',
    "10": '<p>"Enter into the rock and hide in the dust from before the terror of YHWH, and from the splendor of his majesty." Revelation 6:15-17, describing the sixth seal, reproduces this imagery with striking exactness: "Then the kings of the earth and the great ones and the generals and the rich and the powerful, and everyone, slave and free, hid themselves in the caves and among the rocks of the mountains, calling to the mountains and rocks, \'Fall on us and hide us from the face of him who is seated on the throne, and from the wrath of the Lamb, for the great day of their wrath has come, and who can stand?\'" The "wrath of the Lamb" (Rev 6:16) is the NT\'s most striking Christological transformation of the Day of YHWH: the Servant of Isaiah 53 who bore the wrath is also the Lamb who executes it.</p>',
    "11": '<p>"The haughty looks of man shall be brought low, and the lofty pride of men shall be humbled, and YHWH alone will be exalted in that day." The elevation of YHWH alone (<em>wĕniśgaḇ Yhwh lĕḇaddô</em>) is the theological claim that the NT applies to Christ: Phil 2:9-11 ("God has highly exalted him and bestowed on him the name that is above every name, so that at the name of Jesus every knee should bow"). The humbling of human pride is the form Christ\'s exaltation takes — the cross is both the lowest point of human humiliation of Christ and the moment of his highest glorification (John 12:23-24: "the hour has come for the Son of Man to be glorified"). Jas 4:6 and 1 Pet 5:5 both cite "God opposes the proud but gives grace to the humble" (Prov 3:34) — the same wisdom principle that structures Isaiah 2.</p>',
    "12": '<p>"For YHWH of hosts has a day against all that is proud and lofty, against all that is lifted up — and it shall be brought low." The "Day of YHWH of hosts" against all pride is the theological engine of eschatology. In the NT, the Day of the Lord is the day of Christ\'s return: 1 Thess 5:2 ("the day of the Lord will come like a thief in the night"); 2 Pet 3:10 ("the day of the Lord will come like a thief, and then the heavens will pass away with a roar"). The list of specific things brought low in vv.12-16 (cedars of Lebanon, oaks of Bashan, high mountains, lofty towers) functions in NT preaching as the comprehensive catalog of human achievement — no earthly structure, however magnificent, escapes the day of reckoning.</p>',
    "13": '<p>"Against all the cedars of Lebanon, lofty and lifted up; and against all the oaks of Bashan." The cedars of Lebanon are the great trees used for Solomon\'s temple (1 Kings 5:6-10) and for palace construction — they represent civilization\'s highest achievements. In Jesus\'s saying about the Jerusalem temple: "There will not be left here one stone upon another that will not be thrown down" (Matt 24:2), the great structures of religious and human achievement — even the temple — are subject to the Day of the Lord. The "lifted up" (<em>nĕśuʾôt</em>) terminology is the same root used in 52:13 for the exaltation of the Servant — everything human is brought down so the Servant alone can be lifted up.</p>',
    "14": '<p>"Against all the lofty mountains, and against all the uplifted hills." Mountains in biblical cosmology are the places of divine manifestation — Sinai, Zion, Carmel. The eschatological leveling of every mountain (cf. 40:4, "every mountain and hill shall be made low; and the uneven ground shall become level") is the negative form of Zion\'s exaltation in 2:2. In Luke 3:5, the Baptist\'s announcement of the coming of the Lord cites Isaiah 40:3-5, and the mountain-leveling is part of the preparation for the Messiah\'s coming. Judgment and restoration are two sides of the same eschatological act.</p>',
    "15": '<p>"Against every high tower, and against every fortified wall." The tower and wall represent human defensive architecture — the attempt to secure one\'s own life against enemy and divine judgment. Luke 14:28 uses tower-building as a parable for counting the cost of discipleship; the foolish builder fails to account for what it will take. More directly, Jesus\'s pronouncement against the Jerusalem walls (Matt 24:2; Luke 19:43-44: "your enemies will set up a barricade around you and surround you and hem you in on every side") is the fulfillment of the "against every fortified wall" judgment of Isaiah 2:15.</p>',
    "16": '<p>"Against all the ships of Tarshish, and against all the beautiful craft." The ships of Tarshish (probably Tartessus in southern Spain, or a generic term for large ocean-going vessels) represent the reach and wealth of international trade. In Revelation 18:17-19, the merchants and sailors who weep over fallen Babylon are depicted in terms that echo Ezekiel 27 (the Tyre lament) but also this Isaianic tradition: "all shipmasters and seafaring men, sailors and all whose trade is on the sea, stood far off and cried out as they saw the smoke of her burning." Human commercial achievement and maritime power are included in the catalog of what the Day of the Lord sweeps away.</p>',
    "17": '<p>"And the haughtiness of man shall be humbled, and the lofty pride of men shall be brought low, and YHWH alone will be exalted in that day." The repetition of v.11\'s refrain (YHWH alone exalted) creates the chapter\'s structural spine. In NT Christology, the exclusive exaltation of YHWH and the exaltation of the risen Christ are not in tension but are identical — Phil 2:9-11 presents Christ\'s exaltation as the form of YHWH\'s vindication of humble obedience. The "one name" before which every knee bows (2:11, 17) is the name of Jesus, which is also the name above every name (Phil 2:9). The monotheistic intensification ("YHWH alone") becomes the Christological concentration in the NT.</p>',
    "18": '<p>"And the idols shall utterly pass away." The abolition of idols is an eschatological event in Isaiah (cf. 17:7-8; 31:7). In the NT, Paul declares this fulfilled in principle: "we know that an idol has no real existence, and that there is no God but one" (1 Cor 8:4). Col 2:15 reads the cross as the event in which Christ "disarmed the rulers and authorities and put them to open shame, by triumphing over them in him" — the powers behind the idols are already defeated, though their final abolition awaits the return. 1 Cor 15:24-26 traces the sequence: Christ reigns "until he has put all his enemies under his feet" — the idols and the powers they represent are part of this eschatological abolition.</p>',
    "19": '<p>"And people shall enter the caves of the rocks and the holes of the ground, from before the terror of YHWH, and from the splendor of his majesty, when he rises to terrify the earth." The cave-hiding imagery of vv.19-21 is directly quoted in Rev 6:15-16 (see note on v.10). Luke 23:30 applies the related Hosea 10:8 ("they will say to the mountains, \'Cover us,\' and to the hills, \'Fall on us\'") to the coming judgment on Jerusalem: Jesus tells the daughters of Jerusalem to weep not for him but for themselves and their children. The terror of YHWH rising to terrify the earth is the posture of the returning Christ who comes "in flaming fire, inflicting vengeance on those who do not know God" (2 Thess 1:8).</p>',
    "20": '<p>"In that day mankind will cast away their idols of silver and their idols of gold, which they made for themselves to worship, to the moles and to the bats." The casting away of idols — not voluntary devotion but panic-driven abandonment — contrasts with voluntary repentance. In Acts 19:18-19, those who convert in Ephesus burn their magical books publicly; the voluntary casting away of the instruments of idolatry is the repentance that the Isaianic "that day" judgment calls for before the terror comes. The NT consistently presents the church\'s present repentance from idols (1 Thess 1:9: "you turned to God from idols to serve the living and true God") as the anticipatory fulfillment of this eschatological casting away.</p>',
    "21": '<p>"To enter the caverns of the rocks and the clefts of the cliffs, from before the terror of YHWH, and from the splendor of his majesty, when he rises to terrify the earth." The threefold repetition (vv.10, 19, 21) of the cave-hiding formula intensifies the inexorability of the Day. In Rev 6:17 the question "who can stand?" has a Christological answer: "Stand firm in the faith" (1 Cor 16:13); "who are you to pass judgment on the servant of another? It is before his own master that he stands or falls" (Rom 14:4). Those who stand on the Day of the Lord are those who stand in Christ, rooted in the one who himself "rose to terrify the earth" in judgment and rose from the earth in resurrection.</p>',
    "22": '<p>"Stop regarding man in whose nostrils is breath, for of what account is he?" The concluding verse grounds the entire chapter\'s anti-pride argument in creatureliness: <em>nišmāt ʾap</em> (breath of the nostril) is the same phrase used in Gen 2:7 when YHWH breathes into Adam\'s nostrils — the human creature receives life as gift, not as possession. Paul\'s anti-boasting theology rests on this: "no flesh shall boast before God" (1 Cor 1:29); "what do you have that you did not receive? If then you received it, why do you boast as if you did not receive it?" (1 Cor 4:7). James 4:13-14 applies this directly to human planning: "what is your life? For you are a mist that appears for a little time and then vanishes." The entire chapter, in its two-part structure (eschatological pilgrimage, Day of humbling), finds its Christological resolution in the one who "though he was in the form of God, did not count equality with God a thing to be grasped, but emptied himself" (Phil 2:6-7) — the one human who correctly understood that breath is received, not owned, and therefore became the source of life for all.</p>',
  },
}

def main():
    existing = load_comm('mkt-christ', 'isaiah')
    merge_comm(existing, ISAIAH)
    save_comm('mkt-christ', 'isaiah', existing)
    # INTENT: Verify all 22 Isaiah 2 mkt-christ verses present against interlinear
    # CHANGE? If interlinear/isaiah.json ch 2 verse count changes, update expected total
    # VERIFY: Console shows OK with 22 verses; no MISSING output
    il = json.loads((ROOT / 'data' / 'interlinear' / 'isaiah.json').read_text())
    out = json.loads((ROOT / 'data' / 'commentary' / 'mkt-christ' / 'isaiah.json').read_text())
    missing = [v for v in il.get('2', {}) if v not in out.get('2', {})]
    if missing:
        print(f'  MISSING: {missing}')
    else:
        print(f'  OK: all Isaiah 2 mkt-christ verses present ({len(il.get("2", {}))} verses)')

if __name__ == '__main__':
    main()
